#include <bits/stdc++.h>
using namespace std;
const int inf=0x3f3f3f3f,N=10005;
int dp[N][1005];
int x[N],y[N],flag[N],l[N],h[N],ans[N];
int n,m,k;
int main()
{
	cin>>n>>m>>k;
	for(int i=0;i<n;i++)
	{
		cin>>x[i]>>y[i];
	}
	for(int i=1;i<=k;i++)
	{
		int q;
		cin>>q;
		cin>>l[q]>>h[q];
		flag[q]=1;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++) dp[i][j]=inf;
	}
	for(int i=1;i<=m;i++) dp[0][i]=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=x[i-1]+1;j<m;j++) dp[i][j]=min(dp[i][j],min(dp[i-1][j-x[i-1]],dp[i][j-x[i-1]])+1);
		for(int j=m-x[i-1];j<=m;j++) dp[i][m]=min(dp[i][m],min(dp[i-1][j],dp[i][j])+1);
		for(int j=1;j+y[i-1]<=m;j++) dp[i][j]=min(dp[i][j],dp[i-1][j+y[i-1]]);
		if(flag[i])
		{
			for(int j=1;j<=l[i];j++) dp[i][j]=inf;
			for(int j=m;j>=h[i];j--) dp[i][j]=inf;
		}
		ans[i]=inf;
		for(int j=1;j<=m;j++) ans[i]=min(ans[i],dp[i][j]);
		if(ans[i]==inf)
		{
			int cnt=0;
			for(int j=1;j<i;j++) if(flag[j]) cnt++;
			cout<<"0\n"<<cnt;
			return 0;
		}
	}
	cout<<"1\n"<<ans[n];
	return 0;
}
